package org.apache.camel.component.fix;

import org.apache.camel.spi.Configurer;
import org.apache.camel.spi.Metadata;
import org.apache.camel.spi.UriParam;
import org.apache.camel.spi.UriParams;

/**
 * FIX component configuration
 */
@UriParams
@Configurer
public class FixConfiguration implements Cloneable {

    @UriParam(description = "The FIX configuration file path")
    private String configFile;

    @UriParam(description = "The sender company ID (SenderCompID field)")
    private String senderCompID;

    @UriParam(description = "The target company ID (TargetCompID field)")
    private String targetCompID;

    @UriParam(defaultValue = "FIX.4.4",
              description = "The FIX protocol version (e.g., FIX.4.2, FIX.4.4, FIX.5.0)")
    private String fixVersion = "FIX.4.4";

    @UriParam(defaultValue = "30",
              description = "The heartbeat interval in seconds")
    private int heartBeatInterval = 30;

    @UriParam(description = "The socket connection host (for client mode)")
    private String socketConnectHost;

    @UriParam(description = "The socket connection port (for client mode)")
    private int socketConnectPort;

    @UriParam(defaultValue = "true",
              description = "Whether to use a synchronized exchange (request/reply)")
    private boolean synchronous = true;

    @UriParam(label = "advanced",
              description = "Whether to disconnect after each message")
    private boolean disconnect;

    public FixConfiguration() {
    }

    @Override
    public FixConfiguration clone() {
        try {
            return (FixConfiguration) super.clone();
        } catch (CloneNotSupportedException e) {
            throw new RuntimeException(e);
        }
    }

    public String getConfigFile() {
        return configFile;
    }

    public void setConfigFile(String configFile) {
        this.configFile = configFile;
    }

    public String getSenderCompID() {
        return senderCompID;
    }

    public void setSenderCompID(String senderCompID) {
        this.senderCompID = senderCompID;
    }

    public String getTargetCompID() {
        return targetCompID;
    }

    public void setTargetCompID(String targetCompID) {
        this.targetCompID = targetCompID;
    }

    public String getFixVersion() {
        return fixVersion;
    }

    public void setFixVersion(String fixVersion) {
        this.fixVersion = fixVersion;
    }

    public int getHeartBeatInterval() {
        return heartBeatInterval;
    }

    public void setHeartBeatInterval(int heartBeatInterval) {
        this.heartBeatInterval = heartBeatInterval;
    }

    public String getSocketConnectHost() {
        return socketConnectHost;
    }

    public void setSocketConnectHost(String socketConnectHost) {
        this.socketConnectHost = socketConnectHost;
    }

    public int getSocketConnectPort() {
        return socketConnectPort;
    }

    public void setSocketConnectPort(int socketConnectPort) {
        this.socketConnectPort = socketConnectPort;
    }

    public boolean isSynchronous() {
        return synchronous;
    }

    public void setSynchronous(boolean synchronous) {
        this.synchronous = synchronous;
    }

    public boolean isDisconnect() {
        return disconnect;
    }

    public void setDisconnect(boolean disconnect) {
        this.disconnect = disconnect;
    }
}

