    private String fixVersion = "FIX.4.4";

    @UriParam(defaultValue = "30",
              description = "The heartbeat interval in seconds")
    private int heartBeatInterval = 30;

    @UriParam(description = "The socket connection host (for client mode)")
    private String socketConnectHost;

    @UriParam(description = "The socket connection port (for client mode)")
    private int socketConnectPort;

    @UriParam(defaultValue = "true",
              description = "Whether to use a synchronized exchange (request/reply)")
    private boolean synchronous = true;

    @UriParam(label = "advanced",
              description = "Whether to disconnect after each message")
    private boolean disconnect;

    public FixConfiguration() {
    }

    @Override
    public FixConfiguration clone() {
        try {
            return (FixConfiguration) super.clone();
        } catch (CloneNotSupportedException e) {
            throw new RuntimeException(e);
        }
